<?php
$pageTitle='Scheduled Reports';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('scheduled_reports');
$pdo=getDB();
$reports=$pdo->query('SELECT * FROM '.table('saved_reports').' WHERE active=1 ORDER BY report_name')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'');
    if($action==='create_schedule'){
      if(setting('report_schedule_enabled','1')!=='1'){throw new RuntimeException('Report scheduling is disabled in settings.');}
      $code=nextScopedDocumentNumber($pdo,'report_schedule',setting('report_schedule_prefix','RSC'),operationalScope($pdo));$user=currentUser();
      $pdo->prepare('INSERT INTO '.table('report_schedules').' (saved_report_id,schedule_code,schedule_name,frequency,format,recipient_emails,next_run_at,status,created_by) VALUES (?,?,?,?,?,?,?,"active",?)')->execute([(int)$_POST['saved_report_id'],$code,trim((string)$_POST['schedule_name']),trim((string)$_POST['frequency']),trim((string)$_POST['format']),trim((string)$_POST['recipient_emails'],),trim((string)$_POST['next_run_at'])?:null,(int)($user['id']??0)?:null]);
      flash('success','Report schedule created.');
    }elseif($action==='run_schedule'){$result=runReportSchedule($pdo,(int)$_POST['schedule_id']);flash('success','Schedule run '.$result['run_number'].' completed with '.$result['rows'].' rows.');}
    elseif($action==='toggle'){$pdo->prepare('UPDATE '.table('report_schedules').' SET status=CASE WHEN status="active" THEN "inactive" ELSE "active" END WHERE id=?')->execute([(int)$_POST['id']]);flash('success','Schedule status changed.');}
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'scheduled-reports']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/scheduled-reports.php');
}
$schedules=$pdo->query('SELECT s.*,r.report_code,r.report_name,r.report_type FROM '.table('report_schedules').' s LEFT JOIN '.table('saved_reports').' r ON r.id=s.saved_report_id ORDER BY s.created_at DESC LIMIT 150')->fetchAll();
$runs=$pdo->query('SELECT rr.*,s.schedule_code,s.schedule_name FROM '.table('report_schedule_runs').' rr LEFT JOIN '.table('report_schedules').' s ON s.id=rr.report_schedule_id ORDER BY rr.created_at DESC LIMIT 100')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Automated Reporting</div><h2 class="h4 mb-1">Scheduled Reports</h2><p class="text-secondary mb-0">Create recurring report schedules and run them manually before connecting cron/email delivery.</p></div><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/cron-runner.php"><?php echo t('Cron Runner', 'مشغل Cron'); ?></a></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="create_schedule"><h2 class="h5 mb-3">Create Schedule</h2><label class="form-label">Saved Report</label><select class="form-select mb-2" name="saved_report_id"><?php foreach($reports as $report): ?><option value="<?php echo (int)$report['id']; ?>"><?php echo esc($report['report_code'].' · '.$report['report_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="schedule_name" placeholder="Schedule name" required><select class="form-select mb-2" name="frequency"><option value="daily">Daily</option><option value="weekly" selected>Weekly</option><option value="monthly">Monthly</option></select><select class="form-select mb-2" name="format"><option value="csv">CSV / Excel</option><option value="pdf">PDF Print View</option></select><textarea class="form-control mb-2" name="recipient_emails" rows="2" placeholder="email1@example.com, email2@example.com"></textarea><label class="form-label">Next Run At</label><input class="form-control mb-3" type="datetime-local" name="next_run_at"><button class="btn btn-brand w-100">Create Schedule</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Schedules</h2><table class="table align-middle"><thead><tr><th>Schedule</th><th>Report</th><th>Frequency</th><th>Next Run</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($schedules as $s): ?><tr><td><strong><?php echo esc($s['schedule_code']); ?></strong><div class="small text-secondary"><?php echo esc($s['schedule_name']); ?></div></td><td><?php echo esc($s['report_name']); ?></td><td><?php echo esc($s['frequency'].' · '.$s['format']); ?></td><td><?php echo esc($s['next_run_at']?:'Manual'); ?></td><td><span class="badge bg-<?php echo esc(statusTone($s['status'])); ?>"><?php echo esc($s['status']); ?></span></td><td class="text-end"><form method="post" class="d-inline"><input type="hidden" name="action" value="run_schedule"><input type="hidden" name="schedule_id" value="<?php echo (int)$s['id']; ?>"><button class="btn btn-sm btn-success">Run</button></form> <form method="post" class="d-inline"><input type="hidden" name="action" value="toggle"><input type="hidden" name="id" value="<?php echo (int)$s['id']; ?>"><button class="btn btn-sm btn-outline-secondary">Toggle</button></form></td></tr><?php endforeach; ?><?php if(!$schedules): ?><tr><td colspan="6" class="text-secondary">No schedules yet.</td></tr><?php endif; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Run History</h2><table class="table"><thead><tr><th>Run</th><th>Schedule</th><th>Rows</th><th>File</th><th>Status</th></tr></thead><tbody><?php foreach($runs as $run): ?><tr><td><strong><?php echo esc($run['run_number']); ?></strong><div class="small text-secondary"><?php echo esc($run['created_at']); ?></div></td><td><?php echo esc($run['schedule_code'].' · '.$run['schedule_name']); ?></td><td><?php echo (int)$run['row_count']; ?></td><td><?php echo esc($run['export_path']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($run['status'])); ?>"><?php echo esc($run['status']); ?></span></td></tr><?php endforeach; ?><?php if(!$runs): ?><tr><td colspan="5" class="text-secondary">No schedule runs yet.</td></tr><?php endif; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>